import { create } from 'zustand';

export type GameStatus = 'idle' | 'countdown' | 'playing' | 'gameover' | 'timeout';

interface GameState {
  status: GameStatus;
  score: number; // Time taken in seconds
  distance: number; // Distance covered 0 to 100
  countdown: number; // 3, 2, 1
  setStatus: (status: GameStatus) => void;
  setScore: (score: number) => void;
  setDistance: (distance: number) => void;
  setCountdown: (count: number) => void;
  reset: () => void;
}

export const useGameStore = create<GameState>((set) => ({
  status: 'idle',
  score: 0,
  distance: 0,
  countdown: 3,
  setStatus: (status) => set({ status }),
  setScore: (score) => set({ score }),
  setDistance: (distance) => set({ distance }),
  setCountdown: (countdown) => set({ countdown }),
  reset: () => set({ status: 'idle', score: 0, distance: 0, countdown: 3 }),
}));

import playerIdle from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Idle_(352x32)[frames=11].png';
import playerRun from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Run_(384x32)[frames=12].png';
import playerJump from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Jump_(32x32).png';
import playerFall from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Fall_(32x32).png';
import playerHit from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Hit_(224x32)[frames=7].png';

export const Assets = {
  playerIdle,
  playerRun,
  playerJump,
  playerFall,
  playerHit,
};

import { Boot } from './scenes/Boot';
import { Game as MainGame } from './scenes/Game';
import Phaser from 'phaser';

const config: Phaser.Types.Core.GameConfig = {
  type: Phaser.AUTO,
  width: 960,
  height: 540,
  parent: 'game-container',
  backgroundColor: '#03A9F4',
  physics: {
    default: 'arcade',
    arcade: {
      gravity: { x: 0, y: 1200 },
      debug: false,
    },
  },
  scale: {
    mode: Phaser.Scale.FIT,
    autoCenter: Phaser.Scale.CENTER_BOTH,
  },
  scene: [Boot, MainGame],
};

const StartGame = (parent: string) => {
  return new Phaser.Game({ ...config, parent });
};

export default StartGame;

