import { Scene } from 'phaser';
import { Assets } from '../assets';

export class Boot extends Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    this.load.spritesheet('player_idle', Assets.playerIdle, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('player_run', Assets.playerRun, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('player_jump', Assets.playerJump, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('player_fall', Assets.playerFall, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('player_hit', Assets.playerHit, { frameWidth: 32, frameHeight: 32 });
  }

  create() {
    this.anims.create({ key: 'anim_idle', frames: this.anims.generateFrameNumbers('player_idle', { start: 0, end: 10 }), frameRate: 11, repeat: -1 });
    this.anims.create({ key: 'anim_run', frames: this.anims.generateFrameNumbers('player_run', { start: 0, end: 11 }), frameRate: 12, repeat: -1 });
    this.anims.create({ key: 'anim_jump', frames: this.anims.generateFrameNumbers('player_jump', { start: 0, end: 0 }), frameRate: 1, repeat: 0 });
    this.anims.create({ key: 'anim_fall', frames: this.anims.generateFrameNumbers('player_fall', { start: 0, end: 0 }), frameRate: 1, repeat: 0 });
    this.anims.create({ key: 'anim_hit', frames: this.anims.generateFrameNumbers('player_hit', { start: 0, end: 6 }), frameRate: 10, repeat: 0 });

    this.scene.start('MainGame');
  }
}

import { Scene } from 'phaser';
import { EventBus } from '../EventBus';
import { useGameStore } from '../../store/gameStore';

const GAME_DURATION = 60; // seconds
const TOTAL_DISTANCE = 3000; // pixels to run
const HURDLE_SPACING = 400; // spawn hurdle every X pixels

export class Game extends Scene {
  private player!: Phaser.Physics.Arcade.Sprite;
  private hurdles!: Phaser.Physics.Arcade.Group;
  private cursors!: Phaser.Types.Input.Keyboard.CursorKeys;

  private isGameRunning = false;
  private playerSpeed = 0;
  private readonly MAX_SPEED = 400;
  private readonly ACCEL = 10;
  private readonly DECEL = 5;
  private distanceCovered = 0;
  private startTime = 0;
  private isHit = false;

  private bgGraphics!: Phaser.GameObjects.Graphics;
  private trackGraphics!: Phaser.GameObjects.Graphics;
  private groundY = 400;

  private nextHurdleDist = HURDLE_SPACING;

  constructor() {
    super('MainGame');
  }

  create() {
    this.distanceCovered = 0;
    this.playerSpeed = 0;
    this.isGameRunning = false;
    this.isHit = false;
    this.nextHurdleDist = HURDLE_SPACING;

    // Background sky is configured in main.ts
    // Draw track
    this.trackGraphics = this.add.graphics();
    this.drawTrack();

    this.player = this.physics.add.sprite(150, this.groundY - 32, 'player_idle');
    this.player.setScale(2);
    this.player.setCollideWorldBounds(true);
    // adjust hitbox
    (this.player.body as Phaser.Physics.Arcade.Body).setSize(16, 24).setOffset(8, 8);
    this.player.play('anim_idle');

    this.hurdles = this.physics.add.group({ allowGravity: false });

    // Colliders
    this.physics.add.overlap(this.player, this.hurdles, this.hitHurdle, undefined, this);

    // Input
    this.cursors = this.input.keyboard!.createCursorKeys();
    this.input.keyboard!.addCapture('LEFT,RIGHT,SPACE');

    // Listen for UI events
    EventBus.on('start-game', this.startGame, this);

    // Handle animation complete
    this.player.on('animationcomplete-anim_hit', () => {
      this.isHit = false;
    });
  }

  drawTrack() {
    this.trackGraphics.clear();
    const width = this.scale.width;
    const height = this.scale.height;

    // Draw ground
    this.trackGraphics.fillStyle(0x8D6E63); // Dirt color
    this.trackGraphics.fillRect(0, this.groundY, width, height - this.groundY);

    // Draw lines for speed illusion
    this.trackGraphics.lineStyle(2, 0xFFFFFF, 0.5);
    const offset = -(this.distanceCovered % 100);
    for (let i = 0; i < width + 100; i += 100) {
      this.trackGraphics.strokeLineShape(new Phaser.Geom.Line(i + offset, this.groundY + 10, i + offset - 20, this.groundY + 40));
    }
  }

  startGame() {
    this.isGameRunning = true;
    this.distanceCovered = 0;
    this.playerSpeed = 0;
    this.startTime = this.time.now;
    this.nextHurdleDist = HURDLE_SPACING;

    // clear existing hurdles
    this.hurdles.clear(true, true);

    this.player.play('anim_run');
  }

  hitHurdle(player: any, hurdle: any) {
    if (this.isHit) return;
    this.isHit = true;

    // Hit penalty
    this.playerSpeed = Math.max(50, this.playerSpeed * 0.3); // reduce speed
    this.player.play('anim_hit');

    // Visual effect: screen shake
    this.cameras.main.shake(100, 0.01);
  }

  spawnHurdle(xPos: number) {
    const hurdle = this.hurdles.create(xPos, this.groundY - 16, null);
    hurdle.setVisible(false); // We'll draw it ourselves or use a rect
    const g = this.add.graphics();
    g.lineStyle(4, 0x1A237E);
    g.fillStyle(0xFFFFFF);
    g.fillRect(-8, -32, 16, 32);
    g.strokeRect(-8, -32, 16, 32);
    g.fillStyle(0xFF5722);
    g.fillRect(-4, -28, 8, 8);

    g.generateTexture('hurdle_tex', 24, 40);
    g.destroy();

    hurdle.setTexture('hurdle_tex');
    (hurdle.body as Phaser.Physics.Arcade.Body).setSize(16, 32).setOffset(4, 4);
    hurdle.x = xPos;
  }

  update(time: number, delta: number) {
    if (!this.isGameRunning) return;

    // Timer check
    const elapsedSec = (time - this.startTime) / 1000;
    if (elapsedSec >= GAME_DURATION) {
      this.finishGame(true);
      return;
    }

    const isOnGround = (this.player.body as Phaser.Physics.Arcade.Body).blocked.down;

    // Movement controls (Left/Right to accelerate)
    if (!this.isHit && isOnGround) {
      if (this.cursors.left.isDown || this.cursors.right.isDown) {
        this.playerSpeed = Math.min(this.MAX_SPEED, this.playerSpeed + this.ACCEL);
      } else {
        this.playerSpeed = Math.max(0, this.playerSpeed - this.DECEL);
      }
    }

    // Jump
    if (Phaser.Input.Keyboard.JustDown(this.cursors.space) && isOnGround) {
      this.player.setVelocityY(-600);
      this.player.play('anim_jump');
    }

    // Animation state update
    if (!this.isHit) {
      if (isOnGround) {
        if (this.playerSpeed > 0 && this.player.anims.currentAnim?.key !== 'anim_run') {
          this.player.play('anim_run');
        } else if (this.playerSpeed === 0 && this.player.anims.currentAnim?.key !== 'anim_idle') {
          this.player.play('anim_idle');
        }
      } else {
        if (this.player.body!.velocity.y > 0 && this.player.anims.currentAnim?.key !== 'anim_fall') {
          this.player.play('anim_fall');
        }
      }
    }

    // Move distance
    const distDelta = (this.playerSpeed * delta) / 1000;
    this.distanceCovered += distDelta;

    // Hurdle spawning and movement
    if (this.distanceCovered >= this.nextHurdleDist && this.distanceCovered < TOTAL_DISTANCE - 500) {
      this.spawnHurdle(this.scale.width + 50);
      this.nextHurdleDist += HURDLE_SPACING + Math.random() * 200; // varied spacing
    }

    this.hurdles.getChildren().forEach((child: any) => {
      child.x -= distDelta;
      if (child.x < -50) {
        child.destroy();
      }
    });

    // Redraw track for scroll effect
    this.drawTrack();

    // Check finish line
    if (this.distanceCovered >= TOTAL_DISTANCE) {
      this.finishGame(false);
    }

    // Sync UI with Zustand
    // Throttle Zustand updates somewhat to avoid 60fps React renders, but it's small state
    // Let's only update every 100ms or so, actually store.setState works fine, but let's do simple sync
    const store = useGameStore.getState();
    const pct = Math.min(100, (this.distanceCovered / TOTAL_DISTANCE) * 100);
    store.setDistance(pct);
    store.setScore(elapsedSec);
  }

  finishGame(isTimeout: boolean) {
    this.isGameRunning = false;
    this.player.play('anim_idle');
    this.playerSpeed = 0;
    const store = useGameStore.getState();
    if (isTimeout) {
      store.setStatus('timeout');
    } else {
      store.setStatus('gameover');
    }
  }

  shutdown() {
    EventBus.off('start-game', this.startGame, this);
  }
}

