import React, { useEffect, useRef } from 'react';
import StartGame from './game/main';
import { useGameStore } from './store/gameStore';
import { EventBus } from './game/EventBus';

function App() {
  const initialized = useRef(false);
  const { status, score, distance, countdown, setStatus, setCountdown, reset } = useGameStore();

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    const game = StartGame('game-container');

    return () => {
      game.destroy(true);
      initialized.current = false;
    };
  }, []);

  const handleStart = () => {
    reset();
    setStatus('countdown');
    let count = 3;
    setCountdown(count);

    const timer = setInterval(() => {
      count -= 1;
      if (count > 0) {
        setCountdown(count);
      } else {
        clearInterval(timer);
        setStatus('playing');
        EventBus.emit('start-game');
      }
    }, 1000);
  };

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-[#03A9F4]">
      {/* Game Canvas Container */}
      <div id="game-container" className="absolute inset-0 w-full h-full" />

      {/* UI Overlay */}
      <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center">

        {/* HUD - Playing */}
        {status === 'playing' && (
          <>
            <div className="absolute top-8 text-6xl font-black italic text-white" style={{ WebkitTextStroke: '2px #1A237E' }}>
              {score.toFixed(2)}s
            </div>
            <div className="absolute bottom-8 w-1/2 max-w-lg h-6 bg-[#F9F7F1] border-4 border-[#1A237E] rounded-full overflow-hidden">
              <div 
                className="h-full bg-[#03A9F4] transition-all duration-100 ease-linear"
                style={{ width: `${distance}%` }}
              />
            </div>
          </>
        )}

        {/* Start Screen */}
        {status === 'idle' && (
          <div className="pointer-events-auto bg-[#F9F7F1] p-8 rounded-3xl border-4 border-[#1A237E] shadow-[0_8px_0_#1A237E] flex flex-col items-center gap-6">
            <h1 className="text-4xl font-black italic text-[#1A237E] tracking-wider">K12 田径冲刺</h1>
            <div className="text-[#1A237E] text-center font-bold">
              <p>← → 交替按键加速</p>
              <p>空格键 跨越障碍</p>
              <p>60秒内到达终点！</p>
            </div>
            <button 
              onClick={handleStart}
              className="mt-4 px-8 py-3 bg-[#FF5722] text-white text-2xl font-black italic rounded-2xl border-4 border-[#1A237E] shadow-[0_6px_0_#1A237E] active:translate-y-2 active:shadow-none transition-all"
            >
              立即开始
            </button>
          </div>
        )}

        {/* Countdown */}
        {status === 'countdown' && (
          <div className="text-9xl font-black italic text-[#FF5722] animate-pulse" style={{ WebkitTextStroke: '4px #1A237E' }}>
            {countdown}
          </div>
        )}

        {/* Game Over / Timeout Screen */}
        {(status === 'gameover' || status === 'timeout') && (
          <div className="pointer-events-auto bg-[#F9F7F1] p-8 rounded-3xl border-4 border-[#1A237E] shadow-[0_8px_0_#1A237E] flex flex-col items-center gap-6">
            <h2 className="text-3xl font-black italic text-[#1A237E]">
              {status === 'timeout' ? '时间到！' : '抵达终点！'}
